"""GET /api/market/<symbol> — real-time market data and company details."""

import logging
from datetime import datetime, timezone

from flask import Blueprint, jsonify

from app.auth.middleware import require_auth
from app.middleware.rate_limit import limiter
from app.services.market_data import PolygonClient

logger = logging.getLogger("signal.market")

market_bp = Blueprint("market", __name__)

# Singleton client — disabled gracefully when POLYGON_API_KEY is unset
_polygon = PolygonClient()


@market_bp.route("/api/market/<symbol>")
@require_auth
@limiter.limit("60 per minute")
def market_snapshot(symbol: str):
    """Return real-time price data for a ticker symbol."""
    if not _polygon.enabled:
        return jsonify({
            "error": "Market data service unavailable",
            "message": "Polygon.io integration is not configured",
        }), 503, {"Retry-After": "60"}

    data = _polygon.get_ticker_snapshot(symbol)
    if data is None:
        return jsonify({
            "error": "Ticker not found",
            "message": f"No market data available for symbol '{symbol.upper()}'",
        }), 404

    data["updated_at"] = datetime.now(timezone.utc).isoformat()
    return jsonify(data)


@market_bp.route("/api/market/<symbol>/details")
@require_auth
@limiter.limit("60 per minute")
def market_details(symbol: str):
    """Return company fundamentals for a ticker symbol."""
    if not _polygon.enabled:
        return jsonify({
            "error": "Market data service unavailable",
            "message": "Polygon.io integration is not configured",
        }), 503, {"Retry-After": "60"}

    data = _polygon.get_ticker_details(symbol)
    if data is None:
        return jsonify({
            "error": "Ticker not found",
            "message": f"No company details available for symbol '{symbol.upper()}'",
        }), 404

    return jsonify(data)


@market_bp.route("/api/market/<symbol>/financials")
@require_auth
@limiter.limit("60 per minute")
def market_financials(symbol: str):
    """Return earnings and financial ratios for a ticker symbol."""
    if not _polygon.enabled:
        return jsonify({
            "error": "Market data service unavailable",
            "message": "Polygon.io integration is not configured",
        }), 503, {"Retry-After": "60"}

    financials = _polygon.get_financials(symbol)
    earnings = _polygon.get_earnings(symbol)

    if financials is None and earnings is None:
        return jsonify({
            "error": "Ticker not found",
            "message": f"No financial data available for symbol '{symbol.upper()}'",
        }), 404

    return jsonify({
        "symbol": symbol.upper(),
        "financials": financials,
        "earnings": earnings.get("earnings", []) if earnings else [],
    })


@market_bp.route("/api/market/<symbol>/competitors")
@require_auth
@limiter.limit("60 per minute")
def market_competitors(symbol: str):
    """Return competitor comparison data for a ticker symbol."""
    if not _polygon.enabled:
        return jsonify({
            "error": "Market data service unavailable",
            "message": "Polygon.io integration is not configured",
        }), 503, {"Retry-After": "60"}

    competitors = _polygon.get_related_companies(symbol)
    if competitors is None:
        return jsonify({
            "error": "Ticker not found",
            "message": f"No competitor data available for symbol '{symbol.upper()}'",
        }), 404

    return jsonify({
        "symbol": symbol.upper(),
        "competitors": competitors,
    })

"""Tests for Polygon.io market data service."""

from unittest.mock import MagicMock, patch

from app.services.market_data import PolygonClient


class TestPolygonClientDisabled:
    """Tests when POLYGON_API_KEY is not set."""

    def test_disabled_when_no_api_key(self):
        client = PolygonClient(api_key="")
        assert client.enabled is False

    def test_snapshot_returns_none_when_disabled(self):
        client = PolygonClient(api_key="")
        assert client.get_ticker_snapshot("AAPL") is None

    def test_details_returns_none_when_disabled(self):
        client = PolygonClient(api_key="")
        assert client.get_ticker_details("AAPL") is None


class TestPolygonClientEnabled:
    """Tests with a mocked API key."""

    def _make_client(self) -> PolygonClient:
        return PolygonClient(api_key="test-key")

    def test_enabled_with_api_key(self):
        client = self._make_client()
        assert client.enabled is True

    @patch("app.services.market_data.requests.Session.get")
    def test_snapshot_success(self, mock_get: MagicMock):
        mock_resp = MagicMock()
        mock_resp.status_code = 200
        mock_resp.raise_for_status = MagicMock()
        mock_resp.json.return_value = {
            "status": "OK",
            "ticker": {
                "day": {"c": 150.0, "v": 1000000, "vw": 149.5},
                "prevDay": {"c": 148.0},
                "lastTrade": {"p": 150.0},
            },
        }
        mock_get.return_value = mock_resp

        client = self._make_client()
        result = client.get_ticker_snapshot("AAPL")

        assert result is not None
        assert result["symbol"] == "AAPL"
        assert result["price"] == 150.0
        assert result["change"] == 2.0
        assert result["change_percent"] == round((2.0 / 148.0) * 100, 4)
        assert result["volume"] == 1000000
        assert result["vwap"] == 149.5

    @patch("app.services.market_data.requests.Session.get")
    def test_snapshot_caching(self, mock_get: MagicMock):
        mock_resp = MagicMock()
        mock_resp.raise_for_status = MagicMock()
        mock_resp.json.return_value = {
            "status": "OK",
            "ticker": {
                "day": {"c": 150.0, "v": 1000000, "vw": 149.5},
                "prevDay": {"c": 148.0},
                "lastTrade": {"p": 150.0},
            },
        }
        mock_get.return_value = mock_resp

        client = self._make_client()
        client.get_ticker_snapshot("AAPL")
        client.get_ticker_snapshot("AAPL")  # should hit cache

        assert mock_get.call_count == 1

    @patch("app.services.market_data.requests.Session.get")

